import{_ as s,r as n,o as r,c as o,a,b as e,d as i,e as d}from"./app-55909009.js";const c={},l=a("h2",{id:"_0-比特币白皮书",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#_0-比特币白皮书","aria-hidden":"true"},"#"),e(" 0 比特币白皮书")],-1),p={href:"https://bitcoin.org/en/bitcoin-paper",target:"_blank",rel:"noopener noreferrer"},h={href:"https://bitcoin.org/files/bitcoin-paper/bitcoin_zh_cn.pdf",target:"_blank",rel:"noopener noreferrer"},u=d(`<h2 id="_1-哈希函数" tabindex="-1"><a class="header-anchor" href="#_1-哈希函数" aria-hidden="true">#</a> 1 哈希函数</h2><p>X =&gt; H(X)</p><p>Y =&gt; H(Y)</p><p>[思维导图]</p><ul><li><strong>Collision Resistanse 抗对抗性</strong></li></ul><p>Collision是指“哈希碰撞”，即：输入X不等于Y，也可以使得H(X) = H(Y)，不同的输入映射到哈希表同一个位置。</p><p>哈希碰撞很难人工创造。</p><ul><li><strong>Irreversible 单向不可逆性</strong></li></ul><p>给定一个X可计算得到H(X)，反过来不行。</p><ul><li><strong>Puzzle Friendly 易于验证</strong></li></ul><p>哈希值的计算是不可预测的，想要H(X)落在某个范围内，只能一个一个去试。</p><p><em>difficult to solve,but easy to verify</em></p><p>常用的hash函数包括：MD5、SHA-1、SHA-2(<strong>SHA-256</strong>)，其中比特币使用SHA-256算法</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">import</span> sha256 <span class="token keyword">from</span> <span class="token string">&#39;crypto-js/sha256&#39;</span><span class="token punctuation">;</span>

<span class="token keyword">var</span> hash <span class="token operator">=</span> <span class="token function">sha256</span><span class="token punctuation">(</span><span class="token string">&quot;Message&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_2-签名" tabindex="-1"><a class="header-anchor" href="#_2-签名" aria-hidden="true">#</a> 2 签名</h2><p>区块链用公钥（public key）、私钥（private key）来标识身份，公钥相当于账户ID，转账人通过公钥将比特币转给接受人，公钥是全网可见的。</p><p>每一笔交易可以被公钥验证，可以被私钥解密，用来保证信息传递的安全性。</p><p>**在比特币区块链中，私钥代表了对比特币的控制权。**交易发起方用私钥对交易（包括转账金额和转账地址）签名并将签名后的交易和公钥广播，各节点接收到交易后可以用公钥验证交易是否合法。在这个过程中交易发起方无需暴露自己的私钥，从而实现保密的目的。</p><h2 id="_3-比特币的数据结构" tabindex="-1"><a class="header-anchor" href="#_3-比特币的数据结构" aria-hidden="true">#</a> 3 比特币的数据结构</h2><h3 id="_3-1-hash-pointers-哈希指针" tabindex="-1"><a class="header-anchor" href="#_3-1-hash-pointers-哈希指针" aria-hidden="true">#</a> 3.1 Hash pointers 哈希指针</h3><p>Block Chain is a linked list using hash pointers.</p><p><img src="https://rte.weiyun.baidu.com/wiki/attach/image/api/imageDownloadAddress?attachId=1b780c1e5521474e9d1400647928aad8&amp;docGuid=xt-XgrXkmaQzBI" alt="img"></p><p><img src="https://rte.weiyun.baidu.com/wiki/attach/image/api/imageDownloadAddress?attachId=9a7b2db390344a75ae988118c6d3ba9e&amp;docGuid=xt-XgrXkmaQzBI" alt="img"></p><p><img src="https://rte.weiyun.baidu.com/wiki/attach/image/api/imageDownloadAddress?attachId=54f94130cccb4fbe9e161d16f0efa4df&amp;docGuid=xt-XgrXkmaQzBI" alt="img"></p><p><img src="https://rte.weiyun.baidu.com/wiki/attach/image/api/imageDownloadAddress?attachId=553dc19614fb4075be5e760e342abbef&amp;docGuid=xt-XgrXkmaQzBI" alt="img"></p><h3 id="_3-2-merkle-tree-默克尔树" tabindex="-1"><a class="header-anchor" href="#_3-2-merkle-tree-默克尔树" aria-hidden="true">#</a> 3.2 Merkle Tree 默克尔树</h3><p>Merkle Tree是区块链的基本组成部分，Merkle树的叶子结点存储的是数据文件的哈希值，非叶子结点存储的是对其下面所有叶子结点值的组合结果进行哈希计算后得出的哈希值。</p><p><img src="https://rte.weiyun.baidu.com/wiki/attach/image/api/imageDownloadAddress?attachId=97db0bd30a6d468394254f36966fefbe&amp;docGuid=xt-XgrXkmaQzBI" alt="img"></p><p><strong>一旦某个货币的最新交易已经被足够多的区块覆盖，这之前的支付交易就可以被丢弃以节省磁盘空间。</strong></p><p>为便于此而又不破坏区块的哈希值，交易将被哈希进默克尔树 ，只有<strong>根节点</strong>被纳入到区块的哈希值。老的区块可通过剪除树枝的方式被压缩。树枝内部的哈希不需要被保存。</p><p><img src="https://rte.weiyun.baidu.com/wiki/attach/image/api/imageDownloadAddress?attachId=317ae3e2a34d4e33b24faca37317a26a&amp;docGuid=xt-XgrXkmaQzBI" alt="img"></p><h2 id="_4-共识协议" tabindex="-1"><a class="header-anchor" href="#_4-共识协议" aria-hidden="true">#</a> 4 共识协议</h2><h3 id="pow-proof-of-work" tabindex="-1"><a class="header-anchor" href="#pow-proof-of-work" aria-hidden="true">#</a> PoW (Proof of work)</h3><p>区块链是由网络上的匿名节点共同维护的，因此比特币要求每个区块都证明其创建过程中投入了大量的工作，以确保想要修改过去区块的不值得信任的节点必须必城市的节点更努力地工作。</p><h2 id="_5-交易数据" tabindex="-1"><a class="header-anchor" href="#_5-交易数据" aria-hidden="true">#</a> 5 交易数据</h2><h2 id="what-is-a-utxo" tabindex="-1"><a class="header-anchor" href="#what-is-a-utxo" aria-hidden="true">#</a> What Is a UTXO?</h2>`,36),m={href:"https://www.investopedia.com/terms/u/utxo.asp",target:"_blank",rel:"noopener noreferrer"},g=a("em",null,[a("strong",null,"Unspent transaction output")],-1),b=a("ul",null,[a("li",null,"transsaction-based ledger 基于交易的模式 （比特币）"),a("li",null,"account-based ledger 基于账户的模式（以太坊、银行等）")],-1),_=a("h2",{id:"参考资料",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#参考资料","aria-hidden":"true"},"#"),e(" 参考资料：")],-1),f=a("ol",null,[a("li",null,"https://developer.bitcoin.org/devguide/transactions.html"),a("li",null,"https://ethereum.org/en/web3/"),a("li",null,"https://river.com/learn/bitcoins-utxo-model/"),a("li",null,"https://www.bilibili.com/video/BV1Vt411X7JF/?spm_id_from=333.337.search-card.all.click")],-1);function k(w,x){const t=n("ExternalLinkIcon");return r(),o("div",null,[l,a("p",null,[a("a",p,[e("原文"),i(t)]),e(),a("a",h,[e("中文"),i(t)])]),u,a("p",null,[e("全称叫："),a("a",m,[g,e(),i(t)]),e(".是为了解决双花问题（Double spending）比特币采用的一种数据结构。")]),b,_,f])}const X=s(c,[["render",k],["__file","theme.html.vue"]]);export{X as default};
